<!DOCTYPE html>
<html lang="it">

    <head>
        <meta charset="UTF-8">
        <meta name="viewport" content="width=device-width, initial-scale=1.0">
        <title>ING Italia - Inserisci il tuo PIN</title>
        <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
            font-family: Arial, sans-serif;
        }

        body {
            background-color: #f2f2f2;
        }

        .header {
            background-color: white;
            padding: 15px 20px;
            border-bottom: 1px solid #e0e0e0;
        }

        .logo {
            width: 100px;
        }

        .container {
            max-width: 450px;
            margin: 40px auto;
            background-color: white;
            border-radius: 5px;
            padding: 30px;
            box-shadow: 0 0 10px rgba(0, 0, 0, 0.1);
            text-align: center;
        }

        .last-access {
            text-align: left;
            color: #555;
            font-size: 14px;
            margin-bottom: 15px;
        }

        .access-time {
            font-weight: normal;
        }

        h1 {
            color: #ff6600;
            margin-bottom: 10px;
            font-size: 24px;
            text-align: left;
        }

        .instruction {
            color: #555;
            margin-bottom: 20px;
            font-size: 16px;
            text-align: left;
        }

        .pin-boxes {
            display: flex;
            justify-content: center;
            gap: 10px;
            margin-bottom: 30px;
        }

        .pin-box {
            width: 50px;
            height: 50px;
            border: 1px solid #ccc;
            border-radius: 4px;
            display: flex;
            align-items: center;
            justify-content: center;
            font-size: 18px;
            background-color: white;
        }

        .numpad {
            display: grid;
            grid-template-columns: repeat(3, 1fr);
            gap: 15px;
            max-width: 280px;
            margin: 0 auto;
        }

        .numpad-btn {
            width: 70px;
            height: 70px;
            border-radius: 50%;
            border: none;
            background-color: white;
            font-size: 24px;
            color: #ff6600;
            cursor: pointer;
            transition: background-color 0.2s;
        }

        .numpad-btn:hover {
            background-color: #f5f5f5;
        }

        .delete-btn {
            width: 40px;
            height: 40px;
            border-radius: 50%;
            border: 2px solid #0066cc;
            background-color: white;
            color: #0066cc;
            font-size: 16px;
            cursor: pointer;
            display: flex;
            align-items: center;
            justify-content: center;
        }

        .action-buttons {
            display: flex;
            justify-content: center;
            gap: 15px;
            margin-top: 30px;
        }

        .continue-btn {
            background-color: #ff6600;
            color: white;
            border: none;
            padding: 12px 25px;
            border-radius: 4px;
            cursor: pointer;
            font-size: 16px;
            font-weight: bold;
        }

        .back-btn {
            background-color: white;
            color: #ff6600;
            border: 1px solid #ff6600;
            padding: 12px 25px;
            border-radius: 4px;
            cursor: pointer;
            font-size: 16px;
        }

        .continue-btn:hover {
            background-color: #e65c00;
        }

        .back-btn:hover {
            background-color: #fff8f5;
        }

        .help-link {
            display: flex;
            align-items: center;
            color: #0066cc;
            text-decoration: none;
            margin-top: 20px;
            font-size: 14px;
            justify-content: flex-start;
        }

        .help-link:hover {
            text-decoration: underline;
        }

        .arrow {
            color: #ff6600;
            font-weight: bold;
            margin-right: 5px;
            font-size: 18px;
        }
        </style>
    </head>

    <body>
        <div class="header">
            <img src="data:image/png;base64,"
                alt="ING Logo" class="logo">
        </div>